// ============================================================================
//  CATÁLOGO DE PROYECTOS Y LOTES DEL ASISTENTE DE CIERRE
// ============================================================================
//
//  Inventario REAL de lotes por proyecto, transcrito del "Listado de precios"
//  oficial (Julio 2026) de cada desarrollador, con su TASA anual y PRIMA mínima.
//  Los factores de cuota se derivan de la tasa (ver config/factores.ts).
//
//  Fuente de la lista general de proyectos: base de datos del portal (Project).
//  Este archivo aporta el detalle de LOTES + condiciones por proyecto; se une
//  con la BD en /api/asistente/proyectos por `id` (= slug del proyecto).
// ----------------------------------------------------------------------------

export interface Lote {
  /** Identificador único dentro del proyecto (para CRM y bloqueo). */
  id: string;
  poligono: string;
  /** Número de lote. Puede ser combinado (ej. "13-14") en algunos proyectos. */
  numero: number | string;
  /** Área en varas cuadradas (V²). */
  areaV2: number;
  /** Precio de contado en US$. */
  precioContado: number;
  calle: string;
  pasaje: string;
}

export interface Proyecto {
  /** Clave estable = slug del proyecto en el portal/BD. */
  id: string;
  nombre: string;
  /** Nombre que aparece en la Carta Compromiso ("Lotificación ..."). */
  lotificacion: string;
  ubicacion: string;
  /** Tasa de interés anual del proyecto (ej. 0.15 = 15%). */
  tasaAnual: number;
  /** Prima mínima del proyecto (ej. 0.10 = 10%). */
  primaMinima: number;
  lotes: Lote[];
}

